#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
const int MAXN = 1e6 + 5;
int n, m, a[MAXN];
ll tr1[MAXN], tr2[MAXN];
void add(int x, int c)
{
	for (int i = x; i < MAXN; i += i & -i) tr1[i] += c, tr2[i] += x * c;
}
ll sum(int x)
{
	ll res = 0;
	for (int i = x; i; i -= i & -i) res += (x + 1) * tr1[i] - tr2[i];
	return res;
}
int main(void)
{
	cin >> n >> m;
	int x, y, d, op;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
		add(i, a[i] - a[i - 1]);
	}
	while (m--)
	{
		cin >> op;
		if (op == 1)
		{
            cin>>x>>y;
			cin >> d;
			add(x, d), add(y + 1, -d);
		}
		else
        {
            cin>>x;
			printf("%lld\n", sum(x) - sum(x - 1));
        }
	}
	return false;
}
